module RefModule(npc, wpcir, clock, resetn, pc);input   [31:0]  npc;
    input           clock, resetn, wpcir;

    output  [31:0]  pc;

    reg     [31:0]  obf_pcreg;

    assign pc = obf_pcreg;

    always @ (posedge clock or negedge resetn) begin
		if (resetn == 0) begin
            obf_pcreg <= -4;
        end else if (wpcir == 0) begin
			obf_pcreg <= npc;
		end else begin
			obf_pcreg <= obf_pcreg;
		end
    end
endmodule
